void cap04_consume(id value);

void cap04_reference_capture_semantics(id _Nonnull owner, id _Nullable maybeOwner, id _Nonnull delegate) {
    void (^handler)(void) = [strong owner, weak maybeOwner, unowned delegate] {
        cap04_consume(owner);
        if (maybeOwner) {
            cap04_consume(maybeOwner);
        }
        cap04_consume(delegate);
    };
    handler();
}
